// // This module decrements the count on each rising edge of the clock when enabled, resetting to max value on reset
module counter(input clk, input reset, input en, output reg [3:0] count);

	always @(posedge clk) begin
		if (reset) begin
			count <= 0;
		end
		else if (en) begin
			count <= count + 1;
		end
	end

endmodule
